def rle_encode(s):
    """Return run-length encoding of string s as list of (char, count) tuples."""
    if not s:
        return []
    result = []
    prev = s[0]
    count = 1
    for ch in s[1:]:
        if ch == prev:
            count += 1
        else:
            result.append((prev, count))
            prev = ch
